import HyperDHT from 'hyperdht';
import b4a from 'b4a';
import z32 from 'z32';
import { createTcpProxy, createUdpFramedProxy } from '@grph-net/net';
import type { Logger } from '@grph-net/net';
import type { KeyPair } from 'hyperdht';

export interface ClientOptions {
  logger?: Logger;
  silent?: boolean;
  key: string;
  secure?: boolean;
}

export interface ConnectOptions {
  port?: number;
  host?: string;
  udp?: boolean;
}

export interface ClientInfo {
  type: 'client';
  state: string | undefined;
  secure: boolean;
  port: number | undefined;
  host: string | undefined;
  protocol: string;
  key: string;
  publicKey: string;
}

export class GrphClient {
  logger: Logger;
  seed: string;
  secure: boolean;
  keyPair: KeyPair | undefined;
  publicKey: Buffer;
  dht: InstanceType<typeof HyperDHT>;
  stats: Record<string, number>;
  proxy: ReturnType<typeof createTcpProxy> | ReturnType<typeof createUdpFramedProxy>['proxySocket'] | null;
  clients: Map<string, unknown> | null;
  state: string | undefined;
  args: ConnectOptions;

  constructor(opts: ClientOptions) {
    this.logger = opts.silent ? { log: () => {} } : (opts.logger || { log: () => {} });
    this.seed = opts.key;
    this.secure = opts.secure || false;

    if (this.secure) {
      this.keyPair = HyperDHT.keyPair(z32.decode(this.seed));
      this.publicKey = this.keyPair.publicKey;
    } else {
      this.publicKey = z32.decode(this.seed);
    }

    this.dht = new HyperDHT({ keyPair: this.keyPair });
    this.stats = {};
    this.proxy = null;
    this.clients = null;
    this.args = {};
  }

  async connect(options: ConnectOptions = {}, callback?: () => void): Promise<void> {
    this.logger.log({
      type: 1,
      msg: `Connecting to key: ${this.seed}, secure: ${this.secure}`,
    });

    let dhtData: Partial<ConnectOptions> = {};
    const dhtValue = await this.get();
    if (dhtValue) {
      dhtData = JSON.parse(dhtValue.value) as Partial<ConnectOptions>;
      this.logger.log({
        type: 0,
        msg: `Retrieved DHT data: ${JSON.stringify(dhtData)}`,
      });
    } else {
      this.logger.log({ type: 2, msg: 'No DHT data retrieved' });
    }

    options.port = options.port ?? dhtData.port ?? 8989;
    options.host = options.host ?? dhtData.host ?? '127.0.0.1';
    options.udp = options.udp ?? dhtData.udp ?? false;
    this.args = options;
    this.state = 'waiting';

    if (!options.udp) {
      this.handleTCP(options, callback);
    } else {
      this.handleUDP(options, callback);
    }
  }

  handleTCP(options: ConnectOptions, callback?: () => void): void {
    this.logger.log({ type: 0, msg: 'Handling TCP connection' });
    this.proxy = createTcpProxy(
      { port: options.port!, host: options.host! },
      () => this.dht.connect(this.publicKey, { reusableSocket: true }),
      { compress: false, logger: this.logger },
      this.stats,
      () => {
        this.state = 'listening';
        this.logger.log({
          type: 1,
          msg: `Proxy listening on ${options.host}:${options.port}`,
        });
        callback?.();
      },
    );
  }

  handleUDP(options: ConnectOptions, callback?: () => void): void {
    this.logger.log({ type: 0, msg: 'Handling UDP connection' });
    const result = createUdpFramedProxy(
      { port: options.port!, host: options.host! },
      () => this.dht.connect(this.publicKey),
      this.logger,
      () => {
        this.state = 'listening';
        this.logger.log({
          type: 1,
          msg: `Proxy listening on ${options.host}:${options.port} for UDP`,
        });
        callback?.();
      },
    );
    this.proxy = result.proxySocket;
    this.clients = result.clients as unknown as Map<string, unknown>;
  }

  async resume(): Promise<void> {
    this.logger.log({ type: 1, msg: 'Resuming client' });
    await this.dht.resume();
    this.state = 'listening';
    this.logger.log({ type: 1, msg: 'Client resumed' });
  }

  async pause(): Promise<void> {
    this.logger.log({ type: 1, msg: 'Pausing client' });
    await this.dht.suspend();
    this.state = 'paused';
    this.logger.log({ type: 1, msg: 'Client paused' });
  }

  async destroy(): Promise<void> {
    this.logger.log({ type: 1, msg: 'Destroying client' });
    await this.dht.destroy();
    if (this.proxy && 'close' in (this.proxy as any)) {
      (this.proxy as any).close();
    }
    if (this.clients) {
      for (const client of this.clients.values()) {
        (client as any).remoteStream?.destroy();
      }
      this.clients.clear();
    }
    this.proxy = null;
    this.clients = null;
    this.state = 'destroyed';
    this.logger.log({ type: 1, msg: 'Client destroyed' });
  }

  async get(opts: Record<string, unknown> = {}): Promise<{ seq: number; value: string } | null> {
    this.logger.log({ type: 0, msg: 'Getting DHT record' });
    const record = await this.dht.mutableGet(this.publicKey, opts);
    if (record) {
      const value = b4a.toString(record.value);
      this.logger.log({
        type: 0,
        msg: `DHT get completed: seq=${record.seq}, value=${value}`,
      });
      return { seq: record.seq, value };
    }
    this.logger.log({ type: 2, msg: 'DHT get: no record found' });
    return null;
  }

  get info(): ClientInfo {
    return {
      type: 'client',
      state: this.state,
      secure: this.secure,
      port: this.args.port,
      host: this.args.host,
      protocol: this.args.udp ? 'udp' : 'tcp',
      key: this.seed,
      publicKey: z32.encode(this.publicKey),
    };
  }

  static async ping(
    key: string,
    dht?: InstanceType<typeof HyperDHT>,
  ): Promise<Record<string, unknown> | null> {
    let ownDht = false;
    if (!dht) {
      dht = new HyperDHT();
      ownDht = true;
    }

    let result: Record<string, unknown> | null = null;
    const keyBuffer = z32.decode(key);

    // Try assuming secure: true first
    let publicKey = HyperDHT.keyPair(keyBuffer).publicKey;
    let record = await dht.mutableGet(publicKey, { latest: true });
    if (record) {
      const value = b4a.toString(record.value);
      try {
        result = JSON.parse(value) as Record<string, unknown>;
        result.protocol = (result as any).udp ? 'udp' : 'tcp';
      } catch {
        // Ignore invalid JSON
      }
    }

    // If no result, try assuming secure: false
    if (!result) {
      publicKey = keyBuffer;
      record = await dht.mutableGet(publicKey, { latest: true });
      if (record) {
        const value = b4a.toString(record.value);
        try {
          result = JSON.parse(value) as Record<string, unknown>;
          result.protocol = (result as any).udp ? 'udp' : 'tcp';
        } catch {
          // Ignore invalid JSON
        }
      }
    }

    if (ownDht) {
      await dht.destroy();
    }
    return result;
  }
}

export default GrphClient;
